    34→  onCreated?: (slider: KeenSliderInstance) => void;
    35→  onPreviousClick?: () => void;
    36→  onNextClick?: () => void;
    37→  onSlideClick?: () => void;
    38→};
    39→
    40→/** [Pigment Carousel](https://pigment.customink.com/?path=/docs/components-carousel--page)
    41→ */
    42→const Carousel: FC<CarouselProps> = ({
    43→  arrows = true,
    44→  arrowPosition = 'inside',
    45→  arrowOffset = 40,
    46→  dots = true,
    47→  lazy = false,
    48→  lazyOffset = 1,
