    66→  const [loaded, setLoaded] = useState<boolean[]>([]);
    67→  const [currentSlide, setCurrentSlide] = useState(0);
    68→  const [keenSliderCallbackRef, instanceRef] = useKeenSlider<HTMLDivElement>({
    69→    initial: 0,
    70→    loop: loop,
    71→    slides: {
    72→      origin: slidesPerView > 1 ? 'auto' : 'center',
    73→      perView: slidesPerView,
    74→      spacing: slidesSpacing,
    75→    },
    76→    animationEnded(slider) {
    77→      setCurrentSlide(slider.track.details.rel);
    78→    },
    79→    slideChanged(slider) {
    80→      setCurrentSlide(slider.track.details.rel);
    81→    },
    82→    created: onCreated,
    83→  });
