    95→  useEffect(() => {
    96→    const new_loaded = [...loaded];
    97→    new_loaded[currentSlide] = true;
    98→    // should set immediate neighbors of current slide, so for lazyOffset === 1 and currentSlide === 0,
    99→    // [<current slide (loaded)>, <set true>, false, false, <set true>]
   100→    for (let i = 1; i < slidesPerView + lazyOffset; i++) {
