   102→      new_loaded[(currentSlide + i + loaded.length) % loaded.length] = true;
   103→    }
   104→    setLoaded(new_loaded);
   105→    // Review by @teichmaa in Sep 2025: This code is 3 years old. Hard to read but has worked so far.
   106→    // Not touching it, keeping the deps non-exhaustive. Do NOT update this code; component soon to be deprecated.
   107→    // eslint-disable-next-line react-hooks/exhaustive-deps
   108→  }, [currentSlide]);
