   110→  const hasThumbs = !!thumbnails?.length;
   111→  const showArrows = slides.length >= 2 && arrows;
   112→
   113→  const cssArrowOffset = typeof arrowOffset === 'number' ? `${arrowOffset}px` : arrowOffset;
   114→
   115→  return (
   116→    <CarouselContainer
   117→      hasThumbs={!!thumbnails?.length}
   118→      thumbSize={thumbSize}
   119→      navigatorSide={navigatorSide}
   120→      sliderHeight={sliderHeight}
   121→      sliderBg={sliderBg}
   122→      sx={sx}
   123→      arrowPosition={arrowPosition}
   124→      arrowOffset={cssArrowOffset}
   125→      {...props}
   126→    >
   127→      <div className="slider" ref={boundingBoxRef} style={sliderStyle}>
   128→        {showArrows ? (
   129→          <Arrows
   130→            instanceRef={instanceRef}
   131→            loop={loop}
   132→            currentSlide={currentSlide}
   133→            position={arrowPosition}
   134→            offset={cssArrowOffset}
   135→            onPreviousClick={onPreviousClick}
   136→            onNextClick={onNextClick}
   137→          />
   138→        ) : null}
   139→        <div ref={keenSliderCallbackRef} className="keen-slider" onClick={onSlideClick}>
   140→          {renderSlides({ lazy, loaded, slides })}
   141→        </div>
   142→        {!hasThumbs && dots && slides.length > 1 ? (
   143→          <Dots number={slides.length} currentSlide={currentSlide} instanceRef={instanceRef} />
   144→        ) : null}
   145→      </div>
   146→
   147→      {hasThumbs && instanceRef.current ? (
   148→        <Navigator
   149→          currentSlide={currentSlide}
   150→          thumbnails={thumbnails}
   151→          thumbSize={thumbSize}
   152→          navigatorSide={navigatorSide}
   153→          instanceRef={instanceRef}
   154→        />
   155→      ) : null}
   156→    </CarouselContainer>
   157→  );
   158→};
   159→
   160→export default Carousel;
